#pragma once
#include "Lic_LicenseSystemAttribs.h"

/* Lic_LicenseSystemAttribs_Helper - the purpose of this class is to help the server code convert streamed 
 * members into a format that it needs to use for backward compatibility with Licensing 3.3 and before. 
 *  
 */
class Lic_LicenseSystemAttribs_Helper : 
	public Lic_LicenseSystemAttribs
{
	CSpdCString TagStream(
		const CSpdCString &wsTag,
		const CSpdCString &wsStream) const
	{
		CSpdCString ws;
		ws += L"<" + wsTag + L">";
		ws += wsStream;
		ws += L"</" + wsTag + L">";

		return ws;
	}
public:
	CSpdCString GetTaggedEventLogAttribsStream() const
	{
		// Licensing 3.3 expects GenerateStreamData_ByLicenseSystemData() to return
		// Streamed EventLog data escaped, then wrapped in the <sE></sE> tag. 
		// Licensing 3.4+ does not need it to be escaped.
		CSpdCString wsStream = GetStreamed_SystemEventLogInfoAttribs();
		CSpdCString wsEscaped = SpdUtils::XmlEscapeString(wsStream);

		return TagStream(L"sE", wsEscaped);
	}
	CSpdCString GetTaggedUsageInfoAttribsStream() const
	{
		return TagStream(L"sU", GetStreamed_UsageInfoAttribs());
	}
};
   
